INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.desc', 'ja', '大型観光バスから降りて写真を1枚撮ってまたバスに乗る旅行に疲れていませんか？Tourgetherでは、地元の人だけが知る穴場スポット、ローカルグルメ、本当のその街の雰囲気を体験できます。現地ガイドと直接つながり、自分だけのオーダーメイド旅行を計画しましょう。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article1.title', 'ja', 'パッケージツアーの物足りなさを解決します', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.desc', 'ja', '一人旅をしたいけど、一人でご飯を食べるのが不安だったり、写真を撮ってくれる人がいなくて残念だった経験はありませんか？「Open to Meet」機能で同じ地域にいる他の旅行者と出会いましょう。趣味が合う人たちと一緒の食事、ツアー、アクティビティで一人旅の寂しさを解消します。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article2.title', 'ja', '一人旅の方のためのつながりプラットフォーム', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.desc', 'ja', 'あなたの街を一番よく知っているのはあなた自身です。Tourgetherでローカルガイドになって、旅行者に特別な体験を提供し、収入を得ましょう。グルメツアー、写真撮影サービス、ショッピング同行、言語通訳など、様々なサービスを登録できます。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article3.title', 'ja', '地元の人も収入を得られるシェアリングエコノミー', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.desc', 'ja', 'エスクロー基盤の決済システムで安心して取引してください。サービス完了まで代金は安全に保管され、問題発生時は紛争解決システムが双方を保護します。レビューシステムと認証済みホストバッジで信頼できる相手を簡単に見つけられます。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article4.title', 'ja', '安全なP2P取引システム', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.desc', 'ja', '写真と一緒に旅の瞬間をフィードで共有し、地図ベースのタイムラインで旅程を可視化しましょう。AI基盤のCineMap機能は写真の位置情報を分析して、映画のような旅行ストーリーボードを自動生成します。旅行後も思い出を簡単に振り返ることができます。', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.article5.title', 'ja', '旅の記録を美しく残しましょう', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.subtitle', 'ja', '旅の本質を取り戻す新しい方法', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
INSERT INTO translations (namespace, key, locale, value, is_reviewed, version) VALUES ('ui', 'landingPage.seoSection.title', 'ja', 'なぜTourgether？', false, 1) ON CONFLICT (namespace, key, locale) DO NOTHING;
